function processData(data, type, format, verbose, dryRun) {
  let result = [];
  for (let i = 0; i < data.length; i++) {
    if (type === 'user') {
      if (data[i].age > 18) {
        if (data[i].active) {
          if (format === 'json') {
            result.push(JSON.stringify(data[i]));
          } else if (format === 'csv') {
            result.push(`${data[i].name},${data[i].age},${data[i].email}`);
          } else {
            result.push(data[i].toString());
          }
        }
      }
    } else if (type === 'order') {
      if (data[i].total > 0) {
        if (data[i].status !== 'cancelled') {
          if (format === 'json') {
            result.push(JSON.stringify(data[i]));
          } else if (format === 'csv') {
            result.push(`${data[i].id},${data[i].total},${data[i].status}`);
          } else {
            result.push(data[i].toString());
          }
        }
      }
    }
    if (verbose) console.log(`Processed item ${i}`);
  }
  if (!dryRun) {
    saveToFile(result);
  }
  return result;
}
